const items = $input.all();
const inputJson = items[0].json;

// 1. ROBUST INPUT RETRIEVAL AND CORRECTED recommendation_text EXTRACTION
// Use the original text for parsing all values
const analystOutputFullText = inputJson.recommendation_text || inputJson.output || ''; 

// Corrected regex to find text between the specified headers
// It looks for "### 📉/📈 Trading Recommendation" and captures everything non-greedily ([\s\S]*?) 
// until it hits "### ⚠️ Risk & Edge Cases" or the end of the string ($).
const recommendationMatch = analystOutputFullText.match(/### 📉\/📈 Trading Recommendation([\s\S]*?)(?=### ⚠️ Risk & Edge Cases|$)/i);
const recommendation_text = recommendationMatch ? recommendationMatch[1].trim() : analystOutputFullText;


// *** NOTE: The input text does NOT contain a 'Current Price', so entry_price will remain 0. ***
// We still use the FULL text for all parsing.
const entryPriceMatch = analystOutputFullText.match(/\*\*Current Price \(MEXC\):\*\*\s*([\d\.]+)/);
const entry_price = entryPriceMatch ? parseFloat(entryPriceMatch[1]) : 0;

// 2. CORRECTED REGEX PATTERNS FOR PRICE EXTRACTION

// Signal Side: Matches "Side:** NEUTRAL to SHORT bias" or "Side:** LONG bias"
const sideMatch = /Side:\*\*\s*(.+?)\s*bias/.exec(analystOutputFullText) || /Side:\*\*\s*(LONG|SHORT|NEUTRAL)/.exec(analystOutputFullText);

let signal_side = 'NEUTRAL';
if (sideMatch) {
    const sideText = sideMatch[1].toUpperCase();
    if (sideText.includes('SHORT')) {
        signal_side = 'SHORT';
    } else if (sideText.includes('LONG')) {
        signal_side = 'LONG';
    } else if (sideText.includes('NEUTRAL')) {
        signal_side = 'NEUTRAL';
    }
} else {
    signal_side = 'UNKNOWN';
}

// Entry Zone: Matches "Entry zone:** Short near 233-235 USDT"
const entryZoneMatch = /Entry zone:\*\*\s*(?:Short|Long)\s*near\s*([\d\.]+)-([\d\.]+)\s*USDT/.exec(analystOutputFullText);
const entry_target_min = entryZoneMatch ? parseFloat(entryZoneMatch[1]) : 0;
const entry_target_max = entryZoneMatch ? parseFloat(entryZoneMatch[2]) : 0;

// Stop-Loss: Matches "Stop-loss:** Above 238 USDT"
const stopLossMatch = /Stop-loss:\*\*\s*(?:Above|Below)\s*([\d\.]+)\s*USDT/.exec(analystOutputFullText);
const stop_loss = stopLossMatch ? parseFloat(stopLossMatch[1]) : 0;

// Take-Profit 1: Matches "1. 228.5 USDT"
const takeProfitMatch = /1\.\s*([\d\.]+)\s*USDT/.exec(analystOutputFullText);
const take_profit_1 = takeProfitMatch ? parseFloat(takeProfitMatch[1]) : 0;


// 3. RETURN THE RESULT
return [{
  json: {
    recommendation_text,
    entry_price, 
    signal_side, 
    entry_target_min, 
    entry_target_max, 
    stop_loss, 
    take_profit_1
  }
}];

